// Validierung: Dateiformat und Größe
const body = $input.first().json;
const allowedMimes = ['audio/mpeg', 'audio/mp3', 'audio/wav', 'audio/ogg', 'audio/webm', 'audio/m4a'];
const maxSizeBytes = 25 * 1024 * 1024; // 25 MB

if (!allowedMimes.includes(body.mimeType)) {
  throw new Error(`Ungültiges Format: ${body.mimeType}. Erlaubt: ${allowedMimes.join(', ')}`);
}

if (body.fileSizeBytes > maxSizeBytes) {
  throw new Error(`Datei zu groß: ${body.fileSizeBytes} Bytes. Max: 25 MB`);
}

return [{ json: {
  ...body,
  blobName: `voice-audio/${Date.now()}_${body.originalFilename || 'voice.mp3'}`,
  idempotencyKey: `voice_intake_${body.checksum || Date.now()}`
}}];

const sttResponse = $input.first().json;
const transcript = sttResponse.DisplayText || sttResponse.NBest?.[0]?.Display || '';
const confidence = sttResponse.NBest?.[0]?.Confidence || 0;

return [{ json: { transcript, confidence, sttStatus: sttResponse.RecognitionStatus } }];

